mapper.update:
SET @column_exists = (
    SELECT COUNT(*) FROM INFORMATION_SCHEMA.COLUMNS
    WHERE TABLE_SCHEMA = DATABASE()
    AND TABLE_NAME = 'workflows'
    AND COLUMN_NAME = #{columnName}
);
SET @sql = IF(@column_exists = 0,
    CONCAT('ALTER TABLE workflows ADD COLUMN ', #{columnName}, ' ', #{columnType}, ' COMMENT \'', #{comment}, '\''),
    'SELECT 1'
);
PREPARE stmt FROM @sql;
EXECUTE stmt;
DEALLOCATE PREPARE stmt;

SET @column_exists = (
    SELECT COUNT(*) FROM INFORMATION_SCHEMA.COLUMNS
    WHERE TABLE_SCHEMA = DATABASE()
    AND TABLE_NAME = 'workflows'
    AND COLUMN_NAME = #{oldName}
);
SET @sql = IF(@column_exists > 0,
    CONCAT('ALTER TABLE workflows CHANGE COLUMN ', #{oldName}, ' ', #{newName}, ' ', #{columnType}, ' COMMENT \'', #{comment}, '\''),
    'SELECT 1'
);
PREPARE stmt FROM @sql;
EXECUTE stmt;
DEALLOCATE PREPARE stmt;

SET @index_exists = (
    SELECT COUNT(*) FROM INFORMATION_SCHEMA.STATISTICS
    WHERE TABLE_SCHEMA = DATABASE()
    AND TABLE_NAME = 'workflows'
    AND INDEX_NAME = #{indexName}
);
SET @sql = IF(@index_exists = 0,
    CONCAT('ALTER TABLE workflows ADD INDEX ', #{indexName}, ' (', #{columnName}, ')'),
    'SELECT 1'
);
PREPARE stmt FROM @sql;
EXECUTE stmt;
DEALLOCATE PREPARE stmt;

SET @column_exists = (
    SELECT COUNT(*) FROM INFORMATION_SCHEMA.COLUMNS
    WHERE TABLE_SCHEMA = DATABASE()
    AND TABLE_NAME = 'workflows'
    AND COLUMN_NAME = #{columnName}
);
SET @sql = IF(@column_exists > 0,
    CONCAT('ALTER TABLE workflows MODIFY COLUMN ', #{columnName}, ' ',
        (SELECT DATA_TYPE FROM INFORMATION_SCHEMA.COLUMNS
         WHERE TABLE_SCHEMA = DATABASE() AND TABLE_NAME = 'workflows' AND COLUMN_NAME = #{columnName}),
        ' COMMENT \'', #{comment}, '\''),
    'SELECT 1'
);
PREPARE stmt FROM @sql;
EXECUTE stmt;
DEALLOCATE PREPARE stmt;
